// Inverse lookup for ultra-fast encoding (Character/Word to Coordinate)
const GLEXICON_REVERSE_CHARS = {};
for (const [coord, char] of Object.entries(GLEXICON_LOOKUP.chars)) {
  if (char) GLEXICON_REVERSE_CHARS[char] = parseInt(coord, 10);
}

const GLEXICON_REVERSE_WORDS = {};
for (const [coord, word] of Object.entries(GLEXICON_LOOKUP.words)) {
  GLEXICON_REVERSE_WORDS[word] = parseInt(coord, 10);
}

/**
 * Encodes a string into an array of coordinate indices
 * @param {string} text 
 * @returns {number[]}
 */
function glexiconEncode(text) {
  // Built-in browser word segmenter
  const segmenter = new Intl.Segmenter('en', { granularity: 'word' });
  const segments = segmenter.segment(text);
  const output = [];

  for (const segment of segments) {
    const term = segment.segment;
    if (segment.isWordLike) {
      const lowerTerm = term.toLowerCase();
      // Check word coordinate
      if (GLEXICON_REVERSE_WORDS[lowerTerm] !== undefined) {
        output.push(GLEXICON_REVERSE_WORDS[lowerTerm]);
      } else {
        // Fallback to character coordinate
        for (const char of term) {
          if (GLEXICON_REVERSE_CHARS[char] !== undefined) {
            output.push(GLEXICON_REVERSE_CHARS[char]);
          }
        }
      }
    } else {
      // Spaces, punctuation, and newlines
      for (const char of term) {
        if (GLEXICON_REVERSE_CHARS[char] !== undefined) {
          output.push(GLEXICON_REVERSE_CHARS[char]);
        }
      }
    }
  }
  return output;
}

/**
 * Decodes an array of coordinates back into the original text
 * @param {number[]} coordinates 
 * @returns {string}
 */
function glexiconDecode(coordinates) {
  let output = "";
  for (const coord of coordinates) {
    if (GLEXICON_LOOKUP.words[coord] !== undefined) {
      output += GLEXICON_LOOKUP.words[coord];
    } else if (GLEXICON_LOOKUP.chars[coord] !== undefined) {
      output += GLEXICON_LOOKUP.chars[coord];
    }
  }
  return output;
}

// Export for extension/module usage
if (typeof module !== 'undefined' && module.exports) {
  module.exports = { GLEXICON_LOOKUP, GLEXICON_REVERSE_CHARS, GLEXICON_REVERSE_WORDS, glexiconEncode, glexiconDecode };
}
